%[text] # 例1.15（Shannon の標本化定理）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example01_15"; % mfilename

%%
%[text] ## 標本化周期の設定
%[text] - $\\Delta\_\\mathrm{t}$: 標本化周期 \
% Sampling period
deltat = 1 %[control:slider:1cb1]{"position":[10,11]} %[output:17749828]
%%
%[text] ## Sinc関数
%[text]  $\\mathrm{sinc}(\\Delta\_\\mathbf{t}^{-1}t) \\colon = \\frac{\\sin(\\pi \\Delta\_\\mathrm{t}^{-1}t)}{\\pi \\Delta\_\\mathrm{t}^{-1}t}$
% Sinc function
if ~license('test','signal_toolbox')
    sinc = @(x) (x==0) + (x~=0).*(sin(pi*x)./(pi*x)); 
end
figure(1) %[output:9693d212]
fplot(@(x) sinc(x/deltat),[-15 15]) %[output:9693d212]
xlabel('Time t') %[output:9693d212]
ylabel('sinc(t/\Delta_t)') %[output:9693d212]
axis([-15 15 -0.5 1.5]) %[output:9693d212]
exportgraphics(gca,fullfile(resfolder,myfilename+"_fig01_01.png")) %[output:9693d212]

%%
%[text] ## 入力信号の設定
%[text]  $u(t) = \\sum\_{k\\in\\mathbb{Z}} c\[k\]\\mathrm{sinc}\n(\\Delta\_\\mathrm{t}^{-1}t-k)$
%[text] シャノンの標本化定理は帯域制限信号
%[text]  $u\\in \\mathrm{span}\\{\\mathrm{sinc}(\\Delta\_\\mathrm{t}^{-1}\\cdot-n)\\}\_n.$
%[text] を対象とする。
% Configuration
ts = -10;
te = 20;
k = 0:floor(10/deltat);
td = linspace(ts,te,(te-ts)*floor(1e3/deltat));
[Ts,K] = ndgrid(td,k);

% Generation of signal
c = rand(size(k));
u = sinc(Ts/deltat - K)*c(:);

% Plot the signal
figure(2) %[output:252ad55c]
plot(td,u) %[output:252ad55c]
xlabel('Time t') %[output:252ad55c]
ylabel('Signal u(t)') %[output:252ad55c]
axis([ts te -0.5 1.5]) %[output:252ad55c]
hold on %[output:252ad55c]

%%
%[text] ## Sinc関数による標本化
%[text]  $u\[n\] = \\Delta\_\\mathrm{t}^{-1}\\int\_{-\\infty}^{\\infty}u(t)\\mathrm{sinc}(\\Delta\_\\mathrm{t}^{-1}t-n)dt$
%[text] 以下では有限なサポート領域および台形則で積分を近似していることに注意
% Trapezoidal numerical integration
s = (1/deltat)*trapz(td,u.*sinc(Ts/deltat-K));

% Plot samples
stem(deltat*k,s,'filled') %[output:1253bdb7]
xlabel('Index n') %[output:1253bdb7]
ylabel('Sequence u[n]') %[output:1253bdb7]
axis([ts te -.5 1.5]) %[output:1253bdb7]
exportgraphics(gca,fullfile(resfolder,myfilename+"_fig01_02.png")) %[output:1253bdb7]

%%
%[text] ## 信号再構成
%[text]  $\\check{u}(t) = \\sum\_{k\\in\\mathbb{Z}} u\[k\]\\mathrm{sinc}\n(\\Delta\_\\mathrm{t}^{-1}t-k)$
% Reconstruct the signal from the samples
ucheck = sinc(Ts/deltat - K)*s(:);

% Plot the signal
figure(3) %[output:5c8cd3fe]
plot(td,u,'b',td,ucheck,'--r',deltat*k,s,'or') %[output:5c8cd3fe]
xlabel('Time t') %[output:5c8cd3fe]
ylabel('Signal u\^(t)') %[output:5c8cd3fe]
axis([ts te -0.5 1.5]) %[output:5c8cd3fe]
legend('Original','Reconstructed','Samples') %[output:5c8cd3fe]
exportgraphics(gca,fullfile(resfolder,myfilename+"_fig01_03.png")) %[output:5c8cd3fe]

